          height:        '20px',
          borderRadius:  '50%',
          background:    'rgba(255,255,255,0.3)',
          transform:     `translate(${mousePos.x}px, ${mousePos.y}px)`,
          pointerEvents: 'none'
        }}
      />
    </>
  );
