"use client";

import React, { FC, useRef, useEffect, useState } from "react";

export interface FractalMountainProps {
  /** Animation speed multiplier */
  speed?: number;
  /** Number of FBM octaves */
  octaves?: number;
  /** Noise frequency scale */
  scale?: number;
  /** Canvas container CSS class */
  className?: string;
  /** Accessible label */
  ariaLabel?: string;
}

const vsSource = `
  attribute vec2 a_position;
  void main() {
    gl_Position = vec4(a_position, 0.0, 1.0);
  }
`;

const fsSource = `
  precision highp float;

  uniform vec2 iResolution;
  uniform float iTime;
  uniform float u_speed;
  uniform float u_octaves;
  uniform float u_scale;

  // Hash & noise functions
  float hash(vec2 p) {
    p = fract(p * vec2(123.34, 456.21));
    p += dot(p, p + 45.32);
    return fract(p.x * p.y);
  }

  float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p) * fract(p) * (3.0 - 2.0 * fract(p));
    float a = hash(i + vec2(0.0, 0.0));
    float b = hash(i + vec2(1.0, 0.0));
    float c = hash(i + vec2(0.0, 1.0));
    float d = hash(i + vec2(1.0, 1.0));
    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
  }

  // Fractal Brownian Motion
  float fbm(vec2 p) {
    float v = 0.0;
    float amp = 0.5;
    float freq = u_scale;
    for (int i = 0; i < 6; i++) {
      if (float(i) >= u_octaves) break;
      v += amp * noise(p * freq);
      freq *= 2.0;
      amp *= 0.5;
    }
    return v;
  }

  void main() {
    vec2 uv = (2.0 * gl_FragCoord.xy - iResolution) / iResolution.y;
    uv.x += iTime * u_speed * 0.2;

    // Landscape height
    float h = fbm(uv * 1.5);

    // Sky gradient
    vec3 sky = mix(
      vec3(0.1, 0.0, 0.2),
      vec3(0.5, 0.1, 0.0),
      uv.y + 0.5
    );

    // Mountain silhouette
    float m = smoothstep(h - 0.01, h, uv.y + 0.2);
    vec3 mountain = vec3(0.05, 0.05, 0.15) * (1.0 - h);

    vec3 color = mix(sky, mountain, m);

    // Sun glow
    vec2 sunPos = vec2(0.0, 0.25);
    float dist = length(uv - sunPos);
    vec3 sun = vec3(1.0, 0.7, 0.3) * (0.1 / dist);
    color += sun;

    // Atmospheric fog
    color = mix(color, sky, smoothstep(0.3, 1.5, uv.y + h));

    gl_FragColor = vec4(color, 1.0);
  }
`;

const FractalMountains: FC<FractalMountainProps> = ({
  speed     = 1,
  octaves   = 5,
  scale     = 2,
  className = "",
  ariaLabel = "Procedural fractal mountains background",
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [error, setError] = useState<string | null>(null);
  const frameId = useRef<number>();
  const startTime = useRef<number>(Date.now());

