// src/components/ui/lissajous-nebula-shader.tsx
"use client";

import { useEffect, useRef } from "react";

declare global {
  interface Window {
    THREE: any;
  }
}

/**
 * LissajousNebulaShader
 *
 * Full-screen swirling nebula built from Lissajous curves.
 * Loads Three.js from CDN and renders a dynamic, color-cycling background.
 */
export function LissajousNebulaShader() {
  const containerRef = useRef<HTMLDivElement>(null);
  const sceneRef = useRef<{
    renderer?: any;
    scene?: any;
    camera?: any;
    uniforms?: any;
    rafId?: number;
  }>({});

  useEffect(() => {
    // 1) Load Three.js from CDN
    const script = document.createElement("script");
    script.src = "https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js";
    script.onload = initThree;
    document.head.appendChild(script);

    // Cleanup on unmount
    return () => {
      if (sceneRef.current.rafId) cancelAnimationFrame(sceneRef.current.rafId);
      sceneRef.current.renderer?.dispose();
      document.head.removeChild(script);
    };
  }, []);

  function initThree() {
    if (!window.THREE || !containerRef.current) return;
    const THREE = window.THREE;
    const container = containerRef.current;
    container.innerHTML = "";

    // 2) Camera, scene, clock
    const camera = new THREE.OrthographicCamera(-1, 1, 1, -1, 0, 1);
    const scene = new THREE.Scene();
    const clock = new THREE.Clock();

    // 3) Uniforms
    const uniforms = {
      iTime: { value: 0 },
      iResolution: { value: new THREE.Vector2() },
    };

    // 4) Shaders
    const vertexShader = `
      varying vec2 vUv;
      void main() {
        vUv = uv;
        gl_Position = vec4(position, 1.0);
      }
    `;
    const fragmentShader = `
      precision highp float;
      uniform vec2 iResolution;
      uniform float iTime;
      varying vec2 vUv;

      // Custom palette function
      vec3 palette(float t) {
        return 0.5 + 0.5 * cos(
          6.28318 * (
            vec3(0.7, 0.4, 1.2) * t +
            vec3(0.0, 0.33, 0.67)
          )
        );
      }

      void mainImage(out vec4 O, in vec2 uv) {
        // Normalize coords to –1..1
        vec2 p = uv * 2.0 - 1.0;
        p.x *= iResolution.x / iResolution.y;

        float t = iTime * 0.2;

        // Lissajous pattern warp
        float lx = sin(p.x * 3.0 + t) + cos(p.y * 5.0 - t * 1.5);
        // Radial swirl
        float r = length(p);
        float swirl = sin(6.28318 * (r * 4.0 - t) + lx * 2.0);

        // Edge softness
        float edge = smoothstep(0.2, 0.22, abs(swirl));

        // Final color
        vec3 col = palette(r + swirl * 0.5 + t);
        O = vec4(col * edge, edge);
      }

      void main() {
        mainImage(gl_FragColor, vUv);
      }
    `;

    // 5) Mesh + material
    const mat = new THREE.ShaderMaterial({ uniforms, vertexShader, fragmentShader });
    const quad = new THREE.Mesh(new THREE.PlaneGeometry(2, 2), mat);
    scene.add(quad);

    // 6) Renderer
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setPixelRatio(window.devicePixelRatio);
    container.appendChild(renderer.domElement);

    // 7) Resize handler
    const onResize = () => {
      const { width, height } = container.getBoundingClientRect();
      renderer.setSize(width, height);
      uniforms.iResolution.value.set(width, height);
    };
    window.addEventListener("resize", onResize);
    onResize();

    // 8) Animation loop
    const animate = () => {
      uniforms.iTime.value = clock.getElapsedTime();
      renderer.render(scene, camera);
      sceneRef.current.rafId = requestAnimationFrame(animate);
    };
    animate();

    // Store for cleanup
    sceneRef.current = { renderer, scene, camera, uniforms, rafId: sceneRef.current.rafId };
  }

  return (
    <div
      ref={containerRef}
      className="fixed inset-0 bg-background"
      aria-label="Lissajous nebula shader background"
    />
  );
}


